   271→namespace App\Traits;
   272→
   273→use App\Models\ActivityLog;
   274→
   275→trait LogsActivity
   276→{
   277→    public static function bootLogsActivity(): void
   278→    {
   279→        static::created(function ($model) {
   280→            if (! auth()->check()) {
   281→                return;
   282→            }
   283→
   284→            ActivityLog::create([
   285→                'loggable_type' => get_class($model),
   286→                'loggable_id'   => $model->id,
   287→                'user_id'       => auth()->id(),
   288→                'event'         => 'created',
   289→                'old_values'    => null,
   290→                'new_values'    => $model->getLoggableAttributeValues(),
   291→                'created_at'    => now(),
   292→            ]);
   293→        });
   294→
   295→        static::updating(function ($model) {
   296→            if (! auth()->check()) {
   297→                return;
   298→            }
   299→
   300→            $watchedKeys = $model->loggableAttributes ?? [];
   301→            $changedKeys = array_intersect(array_keys($model->getDirty()), $watchedKeys);
   302→
   303→            if (empty($changedKeys)) {
   304→                return;
   305→            }
   306→
   307→            $oldValues = [];
   308→            $newValues = [];
   309→            foreach ($changedKeys as $key) {
   310→                $oldValues[$key] = $model->getOriginal($key);
   311→                $newValues[$key] = $model->getDirty()[$key];
   312→            }
   313→
   314→            ActivityLog::create([
   315→                'loggable_type' => get_class($model),
   316→                'loggable_id'   => $model->id,
   317→                'user_id'       => auth()->id(),
   318→                'event'         => 'updated',
   319→                'old_values'    => $oldValues,
   320→                'new_values'    => $newValues,
   321→                'created_at'    => now(),
   322→            ]);
   323→        });
   324→
   325→        static::deleting(function ($model) {
   326→            if (! auth()->check()) {
   327→                return;
   328→            }
   329→
   330→            ActivityLog::create([
   331→                'loggable_type' => get_class($model),
   332→                'loggable_id'   => $model->id,
   333→                'user_id'       => auth()->id(),
   334→                'event'         => 'deleted',
   335→                'old_values'    => $model->getLoggableAttributeValues(),
   336→                'new_values'    => null,
   337→                'created_at'    => now(),
   338→            ]);
   339→        });
   340→    }
   341→
   342→    protected function getLoggableAttributeValues(): array
   343→    {
   344→        $watchedKeys = $this->loggableAttributes ?? [];
   345→        return collect($this->getAttributes())->only($watchedKeys)->toArray();
   346→    }
   347→}
